import re, json

with open('/tmp/dashlane_pricing.html', 'r') as f:
    c = f.read()

# Look for JSON-LD structured data with pricing
json_ld = re.findall(r'<script type="application/ld\+json">(.*?)</script>', c, re.DOTALL)
for j in json_ld:
    try:
        data = json.loads(j)
        # Look for price in the data
        def find_prices(obj, path=""):
            if isinstance(obj, dict):
                if 'price' in obj:
                    print(f"Found price at {path}: {obj['price']}")
                if 'name' in obj and 'price' in obj:
                    print(f"  Name: {obj['name']}, Price: {obj['price']}")
                for k, v in obj.items():
                    find_prices(v, f"{path}.{k}")
            elif isinstance(obj, list):
                for i, item in enumerate(obj):
                    find_prices(item, f"{path}[{i}]")
        find_prices(data)
    except json.JSONDecodeError:
        pass

# Also look for price in any JSON-like structure
for m in re.finditer(r'"price":\s*"?\$?([\d.]+)"?', c):
    print(f"Price found: ${m.group(1)}")
PYEOF
